window.helpData = {
    "home": {
        "title": "Help and Support Center",
        "content": "<h2>Help and Support Center</h2><p>Welcome to the Windows XP Simulator Help and Support Center! Find answers to your questions, understand how to work with your computer, and get tips for better performance.</p><div style='background:#FFFDE8; border:1px solid #D6D2B0; padding:10px; border-radius:5px; margin-top:10px;'><h4 style='margin:0 0 5px 0; color:#494949;'>Did you know?</h4><p style='font-size:11px; margin:0;'>You can customize your desktop background by right-clicking an empty area of the desktop, clicking Properties, and then clicking the Desktop tab. This lets you switch between Bliss, Autumn, and other classic themes!</p></div><div style='margin-top: 15px; display:flex; flex-wrap:wrap; gap:10px;'><div style='flex:1; min-width:200px;'><h3 style='color:#215DC6; border-bottom:1px solid #ACA899;'>System Basics</h3><ul style='padding-left:15px; font-size:12px;'><li><a href='#' onclick='showHelpTopic(\"basics\")'>Windows basics</a></li><li><a href='#' onclick='showHelpTopic(\"hardware\")'>Hardware & Peripherals</a></li><li><a href='#' onclick='showHelpTopic(\"networking\")'>Networking and the Web</a></li><li><a href='#' onclick='showHelpTopic(\"performance\")'>Performance & Maintenance</a></li><li><a href='#' onclick='showHelpTopic(\"display\")'>Display Settings</a></li><li><a href='#' onclick='showHelpTopic(\"user_accounts\")'>User Accounts</a></li><li><a href='#' onclick='showHelpTopic(\"accessibility\")'>Accessibility Options</a></li><li><a href='#' onclick='showHelpTopic(\"sfx\")'>System Sound Effects</a></li></ul></div><div style='flex:1; min-width:200px;'><h3 style='color:#215DC6; border-bottom:1px solid #ACA899;'>System Utilities</h3><ul style='padding-left:15px; font-size:12px;'><li><a href='#' onclick='showHelpTopic(\"taskmgr\")'>Task Manager</a></li><li><a href='#' onclick='showHelpTopic(\"cmd\")'>Command Prompt</a></li><li><a href='#' onclick='showHelpTopic(\"catalog\")'>Windows Catalog</a></li><li><a href='#' onclick='showHelpTopic(\"recycling\")'>Recycle Bin</a></li><li><a href='#' onclick='showHelpTopic(\"zipping\")'>Compressing files (Zipping)</a></li><li><a href='#' onclick='showHelpTopic(\"dragdrop\")'>File Drag-and-Drop</a></li><li><a href='#' onclick='showHelpTopic(\"clipbook\")'>Clipbook Viewer</a></li><li><a href='#' onclick='showHelpTopic(\"sysinfo\")'>System Information</a></li><li><a href='#' onclick='showHelpTopic(\"run\")'>Run Command</a></li><li><a href='#' onclick='showHelpTopic(\"defrag\")'>Disk Defragmenter</a></li></ul></div><div style='flex:1; min-width:200px;'><h3 style='color:#215DC6; border-bottom:1px solid #ACA899;'>Applications</h3><ul style='padding-left:15px; font-size:12px;'><li><a href='#' onclick='showHelpTopic(\"ie\")'>Internet Explorer</a></li><li><a href='#' onclick='showHelpTopic(\"excel\")'>Microsoft Excel</a></li><li><a href='#' onclick='showHelpTopic(\"frontpage\")'>Microsoft FrontPage</a></li><li><a href='#' onclick='showHelpTopic(\"notepad\")'>Notepad</a></li><li><a href='#' onclick='showHelpTopic(\"wordpad\")'>WordPad</a></li><li><a href='#' onclick='showHelpTopic(\"paint\")'>Paint</a></li><li><a href='#' onclick='showHelpTopic(\"media\")'>Media Player</a></li><li><a href='#' onclick='showHelpTopic(\"soundrecorder\")'>Sound Recorder</a></li><li><a href='#' onclick='showHelpTopic(\"calc\")'>Calculator</a></li><li><a href='#' onclick='showHelpTopic(\"charmap\")'>Character Map</a></li><li><a href='#' onclick='showHelpTopic(\"remotedesktop\")'>Remote Desktop</a></li></ul></div><div style='flex:1; min-width:200px;'><h3 style='color:#215DC6; border-bottom:1px solid #ACA899;'>Games</h3><ul style='padding-left:15px; font-size:12px;'><li><a href='#' onclick='showHelpTopic(\"solitaire\")'>Solitaire</a></li><li><a href='#' onclick='showHelpTopic(\"minesweeper\")'>Minesweeper</a></li><li><a href='#' onclick='showHelpTopic(\"tetris\")'>Tetris XP</a></li><li><a href='#' onclick='showHelpTopic(\"pinball\")'>3D Pinball</a></li><li><a href='#' onclick='showHelpTopic(\"freecell\")'>FreeCell</a></li><li><a href='#' onclick='showHelpTopic(\"spades\")'>Spades</a></li><li><a href='#' onclick='showHelpTopic(\"hearts\")'>Hearts</a></li></ul></div></div>"
    },
    "cmd": {
        "title": "Command Prompt Help",
        "content": "<h2>Command Prompt Overview</h2><p>The Command Prompt provides a powerful text-based interface to the Windows XP operating system. It allows you to run applications, manage files, and execute scripts.</p><h3>Comprehensive Guide & Detailed Instructions</h3><div><p><b>1. Basic Navigation:</b> Use <code>cd</code> to change directories. E.g., <code>cd Desktop</code> moves you into the Desktop folder. Use <code>cd ..</code> to move up one folder level.</p><p><b>2. File Management:</b> Use <code>dir</code> to list all files and folders in your current directory. Use <code>del [filename]</code> to delete a file. Use <code>mkdir [foldername]</code> to create a new folder.</p><p><b>3. System Commands:</b> Type <code>help</code> to view a list of all supported commands. You can also type <code>ping</code> to check network connectivity, or <code>echo</code> to print text to the screen.</p><p><b>4. Clearing the screen:</b> When your screen gets cluttered, simply type <code>cls</code> and press Enter to clear the console output.</p></div><h3>Advanced Troubleshooting & Shortcuts</h3><ul><li><b>Command History:</b> Use the <b>Up Arrow</b> and <b>Down Arrow</b> keys to cycle through commands you have previously typed. This saves immense amounts of typing!</li><li><b>Tab Completion:</b> Start typing a file or folder name and press <b>Tab</b> to automatically autocomplete it.</li><li><b>Stopping Execution:</b> If a command is running for too long (like a long ping request), press <b>Ctrl+C</b> to interrupt and cancel it.</li></ul><div style='background:#FFFDE8; border:1px solid #D6D2B0; padding:10px; border-radius:5px; margin-top:10px;'><h4 style='margin:0 0 5px 0; color:#494949;'>Did you know?</h4><p style='font-size:11px; margin:0;'>In the real Windows XP, you could change the color of the Command Prompt text by typing <code>color 0A</code> to get a classic \"hacker\" green-on-black terminal look!</p></div>"
    },
    "frontpage": {
        "title": "Microsoft FrontPage Help",
        "content": "<h2>Microsoft FrontPage Overview</h2><p>Microsoft FrontPage is a WYSIWYG (What You See Is What You Get) HTML editor and website administration tool. It allows you to build beautiful, functional web pages without needing to write code manually.</p><h3>Comprehensive Guide & Detailed Instructions</h3><div><p><b>1. Creating a Page:</b> Open FrontPage and start typing directly onto the blank canvas just like a word processor. You can add titles, paragraphs, and lists effortlessly.</p><p><b>2. Formatting:</b> Use the top toolbar to make text <b>Bold</b>, <i>Italic</i>, or <span style='text-decoration:underline;'>Underlined</span>. You can change font families, sizes, and colors to match your web design vision.</p><p><b>3. Adding Media:</b> You can insert images by clicking the Image icon in the toolbar. FrontPage also supports inserting tables to organize your layout into rigid grid structures (a very popular 2000s web design technique!).</p><p><b>4. Saving:</b> Go to File > Save As to export your design into a standard <code>.html</code> file which can be viewed in Internet Explorer.</p></div><h3>Advanced Troubleshooting</h3><ul><li><b>Viewing Source:</b> If you want to see the underlying code, click the \"HTML\" tab at the bottom of the editor. This lets you manually tweak the code generated by FrontPage.</li><li><b>Preview Mode:</b> Click the \"Preview\" tab to see exactly how your page will look when loaded in Internet Explorer before you save it.</li></ul><div style='background:#FFFDE8; border:1px solid #D6D2B0; padding:10px; border-radius:5px; margin-top:10px;'><h4 style='margin:0 0 5px 0; color:#494949;'>Did you know?</h4><p style='font-size:11px; margin:0;'>FrontPage uses proprietary \"FrontPage Server Extensions\" (FPSE) allowing advanced features like hit counters and form submissions without needing backend coding. However, they were notorious for security vulnerabilities!</p></div>"
    },
    "excel": {
        "title": "Microsoft Excel Help",
        "content": "<h2>Microsoft Excel Overview</h2><p>Microsoft Excel is a powerful spreadsheet application used for data entry, complex calculations, accounting, and creating charts.</p><h3>Comprehensive Guide & Detailed Instructions</h3><div><p><b>1. Basic Data Entry:</b> Click on any cell (e.g., A1, B2) and start typing to input text or numbers. Press Enter or Tab to move to the next cell.</p><p><b>2. Formulas:</b> Every formula must start with an equals sign (<code>=</code>). For example, typing <code>=A1+B1</code> will add the values of those two cells together. When you change A1 or B1, the formula updates instantly.</p><p><b>3. Functions:</b> Excel supports powerful built-in functions. <code>=SUM(A1:A5)</code> adds all values in that range. <code>=AVERAGE(B1:B10)</code> calculates the mean. <code>=COUNT(C1:C20)</code> counts the number of cells containing numbers.</p><p><b>4. Formatting:</b> You can format cells as Currency, Percentages, or Dates. Use the formatting toolbar to quickly add borders or change background colors of cells.</p></div><h3>Advanced Troubleshooting</h3><ul><li><b>#DIV/0! Error:</b> This means you are trying to divide a number by zero. Check your formula inputs.</li><li><b>#VALUE! Error:</b> Occurs when a formula expects a number but finds text instead. Ensure your referenced cells only contain valid digits.</li><li><b>CSV Import:</b> You can drag and drop <code>.csv</code> (Comma Separated Value) files directly into the XP simulator window, and Excel will automatically parse them into distinct columns and rows!</li></ul><div style='background:#FFFDE8; border:1px solid #D6D2B0; padding:10px; border-radius:5px; margin-top:10px;'><h4 style='margin:0 0 5px 0; color:#494949;'>Did you know?</h4><p style='font-size:11px; margin:0;'>In Excel 97, there was a hidden Easter Egg that contained a fully playable 3D flight simulator hidden inside the application! You had to scroll to row 97,487 to trigger it.</p></div>"
    },
    "defrag": {
        "title": "Disk Defragmenter Help",
        "content": "<h2>Disk Defragmenter Overview</h2><p>Over time, as files are saved, changed, and deleted, the data on your hard drive becomes scattered (fragmented). Disk Defragmenter reorganizes this data so files are stored in contiguous blocks, speeding up file access and overall system performance.</p><h3>Comprehensive Guide & Detailed Instructions</h3><div><p><b>1. Analyze First:</b> Select your C: drive and click <b>Analyze</b>. The program will scan the drive and show you a visual map of fragmented files (red), contiguous files (blue), system files (green), and free space (white).</p><p><b>2. Reading the Report:</b> After analysis, a dialog will tell you whether defragmentation is recommended based on the percentage of fragmentation.</p><p><b>3. Defragmenting:</b> Click <b>Defragment</b> to start the optimization process. You will see blocks moving in the visualization as files are rearranged physically on the virtual disk platters.</p><p><b>4. Pausing and Stopping:</b> You can pause or stop the process at any time without corrupting your data. The changes made up to that point will be saved.</p></div><h3>Advanced Troubleshooting</h3><ul><li><b>Green Blocks Won't Move:</b> Green blocks represent unmovable system files (like the MFT or pagefile). Disk Defragmenter cannot move these while Windows is running.</li><li><b>Insufficient Free Space:</b> Disk Defragmenter requires at least 15% free space on the drive to effectively reorganize files. If you have less, the process will be extremely slow or fail. Empty your Recycle Bin!</li></ul><div style='background:#FFFDE8; border:1px solid #D6D2B0; padding:10px; border-radius:5px; margin-top:10px;'><h4 style='margin:0 0 5px 0; color:#494949;'>Did you know?</h4><p style='font-size:11px; margin:0;'>Watching the little colored blocks move around in the Windows XP Disk Defragmenter is widely considered one of the most hypnotic and satisfying experiences in early 2000s computing!</p></div>"
    },
    "ie": {
        "title": "Internet Explorer Help",
        "content": "<h2>Internet Explorer Overview</h2><p>Internet Explorer 6 is your gateway to the World Wide Web. It provides a secure and feature-rich environment for browsing websites, downloading files, and accessing web applications.</p><h3>Comprehensive Guide & Detailed Instructions</h3><div><p><b>1. Navigation:</b> Type a website address (URL) into the Address Bar at the top and press Enter or click the \"Go\" button.</p><p><b>2. Toolbars:</b> Use the Back and Forward buttons to navigate your history. The Stop button halts a slow-loading page, and Refresh reloads the current page to get the latest data.</p><p><b>3. Favorites:</b> Click the Favorites icon (the yellow star) to save websites you visit frequently for quick access later.</p><p><b>4. Search:</b> Click the Search button to open the sidebar and query your default search engine.</p></div><h3>Advanced Troubleshooting</h3><ul><li><b>Page Cannot Be Displayed:</b> If you see this error, check your network connection in the Control Panel. The remote server might also be down.</li><li><b>Pop-up Blocker:</b> Ensure your pop-up blocker is enabled to prevent malicious sites from spamming your screen with advertisements.</li><li><b>Clearing Cache:</b> If a page is displaying incorrectly, go to Internet Options and clear your Temporary Internet Files.</li></ul><div style='background:#FFFDE8; border:1px solid #D6D2B0; padding:10px; border-radius:5px; margin-top:10px;'><h4 style='margin:0 0 5px 0; color:#494949;'>Did you know?</h4><p style='font-size:11px; margin:0;'>Internet Explorer 6 launched in 2001 alongside Windows XP and quickly gained over 90% of the web browser market share, completely dominating the \"Browser Wars\" of the era.</p></div>"
    },
    "calc": {
        "title": "Calculator Help",
        "content": "<h2>Calculator Overview</h2><p>The Windows Calculator is a versatile tool that can handle everything from simple grocery arithmetic to complex scientific and programming operations.</p><h3>Comprehensive Guide & Detailed Instructions</h3><div><p><b>1. Standard Mode:</b> The default view handles basic arithmetic (+, -, *, /) and square roots. You can use your keyboard's numpad for rapid data entry.</p><p><b>2. Scientific Mode:</b> Click <b>View > Scientific</b> to expand the calculator. Here you gain access to Trigonometry (sin, cos, tan), Logarithms, Exponents, and Modulo operations.</p><p><b>3. Programmer Mode:</b> Ideal for software engineers. It allows you to convert numbers between Decimal (Dec), Hexadecimal (Hex), Octal (Oct), and Binary (Bin) instantly. It also supports bitwise logic (AND, OR, XOR).</p><p><b>4. Memory Functions:</b><ul><li><b>MS (Memory Store):</b> Saves the current display value.</li><li><b>MR (Memory Recall):</b> Brings the saved value back to the display.</li><li><b>M+ (Memory Add):</b> Adds the current display value to the saved value.</li><li><b>MC (Memory Clear):</b> Wipes the saved memory.</li></ul></p></div><h3>Advanced Troubleshooting & Shortcuts</h3><ul><li><b>Keyboard Focus:</b> If keyboard input isn't working, ensure you have clicked inside the Calculator window to give it active focus.</li><li><b>Copy/Paste:</b> You can press <code>Ctrl+C</code> to copy your calculated result, and <code>Ctrl+V</code> to paste a number directly into the display from another app!</li></ul><div style='background:#FFFDE8; border:1px solid #D6D2B0; padding:10px; border-radius:5px; margin-top:10px;'><h4 style='margin:0 0 5px 0; color:#494949;'>Did you know?</h4><p style='font-size:11px; margin:0;'>If you paste the text <code>1234+5678=</code> into the Calculator, it will automatically process the entire string of keystrokes and output the correct result!</p></div>"
    },
    "paint": {
        "title": "MS Paint Help",
        "content": "<h2>MS Paint Overview</h2><p>Microsoft Paint is a straightforward raster graphics editor. It is widely used for quick image editing, simple drawings, cropping screenshots, and saving images in various formats.</p><h3>Comprehensive Guide & Detailed Instructions</h3><div><p><b>1. Tool Selection:</b> The toolbar on the left contains everything you need. The Pencil is for freehand drawing, the Fill Bucket (Color) floods an enclosed area, and the Line, Rectangle, and Circle tools draw shapes.</p><p><b>2. Color Palette:</b> The bottom bar holds your colors. <b>Left-click</b> a color to set your Primary color (used for the left mouse button). <b>Right-click</b> a color to set your Secondary/Background color (used for the right mouse button and eraser). The visual indicator above the colors shows the current Primary and Secondary selections.</p><p><b>3. Brush Sizes:</b> You can choose between 4 different stroke sizes in the selector box. This size applies to brushes, erasers (which scale to be double the size of the brush), and the outlines of all shapes!</p><p><b>4. Undo & Redo:</b> Made a mistake? Press <code>Ctrl+Z</code> to instantly undo your last action, or <code>Ctrl+Y</code> to redo it!</p></div><h3>Advanced Troubleshooting</h3><ul><li><b>Accidental Fill:</b> If you use the Fill Bucket and your whole screen turns a solid color, it means your shape had a tiny gap in it! Press <code>Ctrl+Z</code> to Undo, close the gap with the pencil tool, and try again.</li></ul><div style='background:#FFFDE8; border:1px solid #D6D2B0; padding:10px; border-radius:5px; margin-top:10px;'><h4 style='margin:0 0 5px 0; color:#494949;'>Did you know?</h4><p style='font-size:11px; margin:0;'>In old versions of MS Paint, holding the <code>Shift</code> key while dragging an active selection would act like a \"stamp\", smearing a trail of the image across your canvas!</p></div>"
    },
    "remotedesktop": {
        "title": "Remote Desktop Help",
        "content": "<h2>Remote Desktop Connection Overview</h2><p>Remote Desktop allows you to connect to a different computer over a network or the Internet and control it as if you were sitting right in front of it.</p><h3>Comprehensive Guide & Detailed Instructions</h3><div><p><b>1. Connection:</b> Launch the application, type the IP address or hostname of the remote computer you wish to connect to, and click Connect.</p><p><b>2. Authentication:</b> You will be prompted to enter a valid username and password for an account that has permission to access the remote system.</p><p><b>3. Full Screen Mode:</b> When connected, the remote computer's desktop will fill your screen. A small connection bar at the top center allows you to minimize or close the session.</p><p><b>4. Options:</b> Click 'Options' before connecting to adjust display settings (like color depth to save bandwidth), local resources (redirecting your local printer to the remote machine), and experience settings.</p></div><h3>Advanced Troubleshooting</h3><ul><li><b>Cannot Connect:</b> Ensure the remote computer is turned on, connected to the network, and has Remote Desktop enabled in its System Properties. Also, check that port 3389 is not blocked by a firewall.</li><li><b>Lag and Slowness:</b> Lower the color depth and disable visual styles in the 'Experience' tab to drastically improve responsiveness over slow connections.</li></ul><div style='background:#FFFDE8; border:1px solid #D6D2B0; padding:10px; border-radius:5px; margin-top:10px;'><h4 style='margin:0 0 5px 0; color:#494949;'>Did you know?</h4><p style='font-size:11px; margin:0;'>Remote Desktop relies on the RDP (Remote Desktop Protocol) which was originally developed by Citrix Systems before Microsoft integrated it deeply into Windows NT and XP.</p></div>"
    },
    "catalog": {
        "title": "Windows Catalog Help",
        "content": "<h2>Windows Catalog / Add or Remove Programs</h2><p>The Windows Catalog (also known as Add or Remove Programs) is your central hub for managing software installed on your system.</p><h3>Comprehensive Guide & Detailed Instructions</h3><div><p><b>1. Viewing Installed Software:</b> Click the <b>Change or Remove Programs</b> tab on the left. The system will populate a list of all currently installed software, their total file size, and how frequently you use them.</p><p><b>2. Uninstalling:</b> To free up hard drive space, select an application from the list and click the <b>Remove</b> button. Follow the wizard to completely delete the software.</p><p><b>3. Adding New Programs:</b> Click the <b>Add New Programs</b> tab to install software from a CD-ROM, Floppy Disk, or the Windows Update server catalog.</p><p><b>4. Windows Components:</b> Use the \"Add/Remove Windows Components\" button to toggle deeply integrated features like Internet Information Services (IIS) or the classic Indexing Service.</p></div><h3>Advanced Troubleshooting</h3><ul><li><b>Program Cannot Be Removed:</b> Sometimes an uninstaller gets corrupted. You may need to run the application's installer again and choose the \"Repair\" option before attempting removal again.</li><li><b>Sorting:</b> You can sort the list by Name, Size, or Frequency of Use by clicking the \"Sort by\" dropdown at the top right.</li></ul><div style='background:#FFFDE8; border:1px solid #D6D2B0; padding:10px; border-radius:5px; margin-top:10px;'><h4 style='margin:0 0 5px 0; color:#494949;'>Did you know?</h4><p style='font-size:11px; margin:0;'>The calculation for \"Frequency of Use\" in Windows XP was notoriously inaccurate, often marking programs you used daily as \"Rarely\" used!</p></div>"
    },
    "soundrecorder": {
        "title": "Sound Recorder Help",
        "content": "<h2>Sound Recorder Overview</h2><p>Sound Recorder is a simple audio capture utility that lets you record your voice, system audio, or external instruments using a microphone, and save them as WAV files.</p><h3>Comprehensive Guide & Detailed Instructions</h3><div><p><b>1. Recording:</b> Ensure your microphone is connected and configured in the Control Panel. Click the red <b>Record</b> button to begin capturing audio. The green waveform will visualize the audio input.</p><p><b>2. Playback:</b> Click the <b>Stop</b> button (black square) to end the recording. Click the <b>Play</b> button (right arrow) to listen to what you just recorded.</p><p><b>3. Editing:</b> Under the Edit menu, you can copy the audio or insert files. Under the Effects menu, you can add Echo, Reverse the audio, or increase/decrease the speed and volume.</p><p><b>4. Saving:</b> Go to File > Save As to export your recording. Sound Recorder natively uses the uncompressed PCM <code>.wav</code> format.</p></div><h3>Advanced Troubleshooting</h3><ul><li><b>No Audio Input:</b> If the green line remains flat while you speak, your microphone is muted or not selected as the default input device in Sounds and Audio Devices in the Control Panel.</li><li><b>60 Second Limit:</b> By default, Sound Recorder can only record 60 seconds of audio. To bypass this, you can record 60 seconds of silence, save it, and then repeatedly insert that file to create a longer blank canvas before recording!</li></ul><div style='background:#FFFDE8; border:1px solid #D6D2B0; padding:10px; border-radius:5px; margin-top:10px;'><h4 style='margin:0 0 5px 0; color:#494949;'>Did you know?</h4><p style='font-size:11px; margin:0;'>The reversing effect in Sound Recorder was often used by children in the 90s and 2000s to \"find hidden subliminal messages\" in popular pop songs!</p></div>"
    },
    "taskmgr": {
        "title": "Task Manager Help",
        "content": "<h2>Windows Task Manager Overview</h2><p>Task Manager is an advanced diagnostic tool that provides details about programs and processes running on your computer. It is your best friend when an application crashes or freezes.</p><h3>Comprehensive Guide & Detailed Instructions</h3><div><p><b>1. Opening Task Manager:</b> Press <code>Ctrl+Shift+Esc</code> on your keyboard, or right-click the taskbar and select \"Task Manager\", or press <code>Ctrl+Alt+Delete</code>.</p><p><b>2. Applications Tab:</b> This shows all your open windows. If a program is marked as \"Not Responding\", click on it and press the <b>End Task</b> button to forcefully close it.</p><p><b>3. Processes Tab:</b> This shows every background executable running. You can sort by CPU or Mem Usage to find out what is slowing your computer down. Use \"End Process\" carefully, as closing a system process like <code>explorer.exe</code> will crash your desktop!</p><p><b>4. Performance Tab:</b> View dynamic green line graphs displaying your CPU Usage History and Page File (RAM) usage. A constantly pegged 100% CPU means your system is struggling.</p></div><h3>Advanced Troubleshooting</h3><ul><li><b>Always on Top:</b> Go to Options > Always on Top to ensure Task Manager stays visible even if a crashed full-screen game is trying to hide it.</li><li><b>Restarting Explorer:</b> If your start menu and taskbar disappear, open Task Manager, go to File > New Task (Run...), type <code>explorer.exe</code>, and press Enter to restart the UI shell.</li></ul><div style='background:#FFFDE8; border:1px solid #D6D2B0; padding:10px; border-radius:5px; margin-top:10px;'><h4 style='margin:0 0 5px 0; color:#494949;'>Did you know?</h4><p style='font-size:11px; margin:0;'>The developer of Task Manager, Dave Plummer, programmed it to bypass the standard Windows API to kill tasks. It's essentially a system-level assassin that can terminate processes when nothing else can!</p></div>"
    },
    "sysinfo": {
        "title": "System Information Help",
        "content": "<h2>System Information Overview</h2><p>System Information (msinfo32) collects and displays detailed configuration information about your hardware, system components, and software environment.</p><p>It is primarily used by IT professionals to diagnose driver conflicts, check BIOS versions, and verify installed RAM without having to open the computer case.</p><h3>Features</h3><ul><li><b>System Summary:</b> Quick look at OS version, CPU, and Memory.</li><li><b>Hardware Resources:</b> Advanced IRQ, DMA, and memory address mapping.</li><li><b>Components:</b> Details on multimedia, display, network, and storage drivers.</li><li><b>Export:</b> Use File > Export to save a report to share with tech support.</li></ul>"
    },
    "display": {
        "title": "Display Properties Help",
        "content": "<h2>Display Properties Overview</h2><p>The Display Properties panel lets you customize the entire visual experience of Windows XP.</p><h3>Customization Options</h3><ul><li><b>Themes:</b> Switch between Windows XP Luna, Windows Classic, or custom themes.</li><li><b>Desktop:</b> Set your background wallpaper. You can stretch, tile, or center images.</li><li><b>Screen Saver:</b> Choose an animation (like 3D Pipes or Starfield) to run when you step away, protecting CRT monitors from burn-in.</li><li><b>Appearance:</b> Change the color scheme (Blue, Olive Green, Silver) and font sizes.</li><li><b>Settings:</b> Adjust your screen resolution (e.g., 800x600 to 1024x768) and color depth (16-bit to 32-bit true color).</li></ul>"
    },
    "user_accounts": {
        "title": "User Accounts Help",
        "content": "<h2>User Accounts Overview</h2><p>The User Accounts control panel allows multiple people to share the same physical computer while keeping their documents, internet favorites, and desktop wallpapers private.</p><h3>Account Types</h3><ul><li><b>Computer Administrator:</b> Has full system rights. Can install software, access all files, and create/delete other user accounts.</li><li><b>Limited Account:</b> Can change their password and desktop, but cannot install software or modify system settings. Recommended for daily use to prevent malware infections.</li><li><b>Guest Account:</b> A temporary account with no password for visitors. Files saved here are easily accessible by anyone.</li></ul><p><b>Tip:</b> Always use a strong password for your Administrator account!</p>"
    },
    "accessibility": {
        "title": "Accessibility Options Help",
        "content": "<h2>Accessibility Options Overview</h2><p>Accessibility Options configure the computer to be easier to use for individuals with vision, hearing, or mobility impairments.</p><h3>Key Features</h3><ul><li><b>StickyKeys:</b> Allows modifier keys (Shift, Ctrl, Alt) to be pressed sequentially rather than simultaneously. Great for users typing with one hand.</li><li><b>FilterKeys:</b> Ignores brief or repeated keystrokes.</li><li><b>ToggleKeys:</b> Plays a tone when Caps Lock, Num Lock, or Scroll Lock is pressed.</li><li><b>SoundSentry:</b> Flashes the screen visually when the system plays an alert sound.</li><li><b>High Contrast:</b> Inverts colors and uses large fonts to improve screen readability.</li></ul>"
    },
    "minesweeper": {
        "title": "Minesweeper Help",
        "content": "<h2>Minesweeper Overview</h2><p>Minesweeper is a logic puzzle game where the objective is to clear a rectangular board containing hidden \"mines\" without detonating any of them, with help from clues about the number of neighboring mines.</p><h3>How to Play</h3><ul><li><b>Left Click:</b> Uncover a square. If a mine is there, you lose.</li><li><b>Right Click:</b> Plant a red flag to mark a suspected mine location.</li><li><b>Both Buttons (Chording):</b> If you click both left and right mouse buttons simultaneously on a revealed number, and you have already placed the correct amount of flags adjacent to it, it will auto-uncover all remaining safe squares around it!</li></ul><p><b>Pro Tip:</b> Start clicking randomly in corners until a large opening appears. Then use logic to deduce the rest!</p>"
    },
    "solitaire": {
        "title": "Solitaire Help",
        "content": "<h2>Klondike Solitaire Overview</h2><p>Solitaire is the classic card-sorting game designed to teach Windows users how to drag-and-drop with a mouse!</p><h3>How to Play</h3><ul><li><b>Goal:</b> Build four foundation piles at the top right, sorted by suit from Ace up to King.</li><li><b>Tableau:</b> Stack cards in descending order, alternating colors (e.g., Black 7 on Red 8).</li><li><b>Deck:</b> Click the deck at the top left to draw cards (draw 1 or draw 3 depending on options).</li><li><b>Kings:</b> Only Kings can be placed on empty tableau spaces.</li></ul><p><b>Did you know?</b> The spectacular cascading card bounce animation upon winning is considered one of the most rewarding sights in computing history.</p>"
    },
    "freecell": {
        "title": "FreeCell Help",
        "content": "<h2>FreeCell Overview</h2><p>FreeCell is a Solitaire variant where nearly every game is theoretically winnable!</p><h3>How to Play</h3><ul><li><b>Goal:</b> Move all cards to the four foundation piles, sorted from Ace to King by suit.</li><li><b>Free Cells:</b> The four spots at the top left are temporary holding areas. You can move any single card to an empty free cell.</li><li><b>Movement:</b> You can move multiple cards at once as a stack ONLY if you have enough empty free cells available to execute the move mathematically.</li></ul>"
    },
            "reversi": {
        "title": "Internet Reversi Help",
        "content": "<h2>Internet Reversi Overview</h2><p>Play the classic game of Reversi (also known as Othello) against a computer opponent or a friend locally.</p><h3>How to Play</h3><div><p><b>1. Objective:</b> The goal is to have the majority of disks turned to display your color when the last playable empty square is filled.</p><p><b>2. Movement:</b> Black always moves first. On your turn, you must place a disk on the board so that there exists at least one straight (horizontal, vertical, or diagonal) occupied line between the new disk and another disk of your color, with one or more contiguous opponent pieces between them.</p><p><b>3. Flipping:</b> All opponent disks that are bounded by your newly placed disk and your pre-existing disk(s) will be flipped to your color.</p><p><b>4. Skipping:</b> If you cannot make a valid move that flanks at least one opponent disk, your turn is skipped. The game ends when the board is completely full or neither player can move.</p></div><h3>Options Menu</h3><ul><li><b>1-Player (Easy):</b> Play against a basic computer opponent.</li><li><b>1-Player (Hard):</b> Play against an advanced computer opponent that uses heuristics.</li><li><b>2-Player (Local):</b> Play against a friend on the same computer.</li></ul>"
    },

    "checkers": {
        "title": "Internet Checkers Help",
        "content": "<h2>Internet Checkers Overview</h2><p>Play the classic game of Checkers against a computer opponent or a friend locally.</p><h3>How to Play</h3><div><p><b>1. Objective:</b> The goal is to capture all of your opponent's pieces or block them so they cannot make a move.</p><p><b>2. Movement:</b> Pieces can only move diagonally forward on the dark squares. Click a piece to select it, then click an empty diagonal square to move.</p><p><b>3. Capturing:</b> If an opponent's piece is diagonally in front of you and the space behind it is empty, you can jump over it to capture it. Multiple jumps are allowed if available.</p><p><b>4. Kinging:</b> When a piece reaches the farthest row on the opponent's side, it becomes a <b>King</b>. Kings can move and jump diagonally both forward and backward.</p></div><h3>Options Menu</h3><ul><li><b>1-Player (Easy):</b> Play against a basic computer opponent.</li><li><b>1-Player (Hard):</b> Play against an advanced computer opponent that looks ahead to make smarter moves.</li><li><b>2-Player (Local):</b> Play against a friend on the same computer. Red goes first.</li></ul>"
    },

    "spades": {
        "title": "Internet Spades Help",
        "content": "<h2>Internet Spades Overview</h2><p>Spades is a trick-taking card game played over the internet with other real players or AI bots.</p><h3>How to Play</h3><ul><li><b>Bidding:</b> Look at your hand and click on the number corresponding to the amount of \"tricks\" (rounds) you think you will win.</li><li><b>Gameplay:</b> Click on a card in your hand to play it. You must follow the lead suit. If you don't have a card of the lead suit, you can play a Spade (which trumps everything) or dump any other card.</li><li><b>Scoring:</b> Your team wins 10 points per trick bid, but you lose 10 points per trick bid if you fall short. Any extra tricks won are \"bags\", which give 1 point each. 10 bags cost you a 100 point penalty!</li></ul>"
    },
    "hearts": {
        "title": "Hearts Help",
        "content": "<h2>Hearts Overview</h2><p>Hearts is an evasion-type trick-taking card game where the goal is to score as FEW points as possible.</p><h3>How to Play</h3><ul><li><b>Passing Phase:</b> Click 3 cards in your hand to select them, then click the \"Pass Selected\" button. You pass to a different opponent every round (Left, Right, Across, Hold).</li><li><b>Gameplay:</b> Click a card to play it when it is your turn. The player with the 2 of Clubs goes first. You MUST follow suit if possible.</li><li><b>Penalties:</b> Every Heart card taken is 1 penalty point. The Queen of Spades is 13 penalty points! Avoid winning tricks with these cards!</li><li><b>Shooting the Moon:</b> If you manage to collect ALL 13 Hearts AND the Queen of Spades, you receive 0 points and everyone else gets 26!</li></ul>"
    },
    "tetris": {
        "title": "Tetris XP Help",
        "content": "<h2>Tetris XP Overview</h2><p>Tetris is the quintessential block-stacking puzzle game.</p><h3>Controls</h3><ul><li><b>Left/Right Arrow:</b> Move the falling tetromino left or right.</li><li><b>Up Arrow:</b> Rotate the piece 90 degrees.</li><li><b>Down Arrow:</b> Soft drop (accelerates falling speed).</li><li><b>Spacebar:</b> Hard drop (instantly slams the piece to the bottom).</li></ul><p><b>Goal:</b> Fill entire horizontal rows to clear them. Clear 4 rows at once with a long \"I\" piece to score a Tetris and earn massive points! The game ends when the blocks stack up to the ceiling.</p>"
    },
    "notepad": {
        "title": "Notepad Help",
        "content": "<h2>Notepad Overview</h2><p>Notepad is the fastest, simplest text editor included with Windows. It edits plain text (.txt) files without any formatting.</p><h3>Key Features</h3><ul><li><b>No formatting:</b> What you type is pure ASCII/UTF-8 data. This makes it perfect for writing code, HTML, or editing system files like <code>boot.ini</code>.</li><li><b>Word Wrap:</b> Go to Format > Word Wrap to stop long sentences from scrolling off the screen horizontally.</li><li><b>Time/Date Log:</b> Press <b>F5</b> to instantly insert the current time and date. <b>Did you know?</b> If you type <code>.LOG</code> on the very first line of a file, Notepad will automatically append the time and date every time you open it!</li></ul>"
    },
    "wordpad": {
        "title": "WordPad Help",
        "content": "<h2>WordPad Overview</h2><p>WordPad is a rich text editor, sitting halfway between Notepad (plain text) and Microsoft Word (full document processor).</p><h3>Key Features</h3><ul><li><b>Rich Text Format (.rtf):</b> WordPad supports bold, italics, font sizing, color changes, and paragraph alignment.</li><li><b>Image Insertion:</b> You can paste or insert pictures directly into the document.</li><li><b>Lightweight:</b> It loads much faster than Microsoft Word, making it ideal for quick letters or formatted notes.</li></ul>"
    },
    "media": {
        "title": "Windows Media Player Help",
        "content": "<h2>Windows Media Player Overview</h2><p>Windows Media Player is the default application for playing digital media files (audio and video) on your computer.</p><h3>Key Features</h3><ul><li><b>Playback Controls:</b> Standard Play, Pause, Stop, Rewind, and Fast Forward controls are at the bottom.</li><li><b>Visualizations:</b> While playing music, the center screen displays mesmerizing geometric animations that react to the beat of the song (e.g., Alchemy, Battery).</li><li><b>Media Library:</b> Organizes your MP3s by Artist, Album, and Genre.</li><li><b>Ripping CDs:</b> You can insert an Audio CD and copy the tracks to your hard drive in WMA or MP3 format.</li></ul>"
    },
    "performance": {
        "title": "Performance and Maintenance Help",
        "content": "<h2>Performance and Maintenance Overview</h2><p>Keep your Windows XP computer running fast and smooth by utilizing these system tools.</p><h3>Best Practices</h3><ul><li><b>Disk Cleanup:</b> Run this monthly to delete temporary internet files, empty the Recycle Bin, and remove old setup logs to reclaim gigabytes of space.</li><li><b>Disk Defragmenter:</b> Run this to optimize the physical location of files on your hard drive platter.</li><li><b>System Restore:</b> If you install a bad driver or get a virus, use System Restore to roll your PC's state back in time to a previous \"restore point\".</li><li><b>Task Scheduler:</b> Automate maintenance tasks to run at 3 AM while you sleep!</li></ul>"
    },
    "hardware": {
        "title": "Hardware Help",
        "content": "<h2>Hardware & Peripherals Help</h2><p>Having trouble with a printer, mouse, or keyboard? This section helps you configure physical devices.</p><h3>Device Manager</h3><p>Right-click My Computer > Properties > Hardware tab > Device Manager. Here you can see every physical chip and peripheral connected to your motherboard. A yellow exclamation mark (!) means a driver is missing or conflicting.</p><h3>Add Hardware Wizard</h3><p>If you plug in a legacy device (like an old parallel port printer) and Windows doesn't automatically detect it (Plug and Play), use the Add Hardware Wizard in the Control Panel to manually force detection.</p>"
    },
    "networking": {
        "title": "Networking and the Web Help",
        "content": "<h2>Networking and the Web Overview</h2><p>Configure your LAN (Local Area Network) and WAN (Internet) connections.</p><h3>Network Connections</h3><p>Located in the Control Panel. Here you will see your \"Local Area Connection\" (Ethernet) or \"Wireless Network Connection\" (Wi-Fi).</p><ul><li><b>IP Configuration:</b> Right click a connection > Properties > TCP/IP to manually set static IP addresses or use DHCP (obtain automatically).</li><li><b>Repair:</b> If your internet drops, right-click the connection and select \"Repair\" to automatically flush DNS and request a new DHCP lease.</li><li><b>Network Setup Wizard:</b> Helps you share an internet connection or printers with other computers in your house.</li></ul>"
    },
    "basics": {
        "title": "Windows Basics Help",
        "content": "<h2>Windows Basics Overview</h2><p>New to Windows XP? Start here to learn the foundational concepts of the operating system.</p><h3>Core Concepts</h3><ul><li><b>The Start Menu:</b> The green button at the bottom left is your launchpad for everything. Programs, settings, and shutdown options live here.</li><li><b>The Taskbar:</b> The blue strip at the bottom holds open windows. Click a button to bring that window to the front. The right side is the \"System Tray\" showing the clock and background apps.</li><li><b>Windows:</b> Every program opens in a frame called a window. You can grab the blue title bar to drag it, click the '_' to minimize it to the taskbar, the square to maximize it to fill the screen, and the red 'X' to close it entirely.</li><li><b>Right-Click Context Menus:</b> Whenever you aren't sure what to do, try right-clicking an item. A menu will appear with relevant actions (Copy, Delete, Properties).</li></ul>"
    },
    "recycling": {
        "title": "Recycle Bin Help",
        "content": "<h2>Working with the Recycle Bin</h2><p>The Recycle Bin acts as a safety net to protect you from accidental data loss.</p><h3>Usage Instructions</h3><ul><li><b>Deleting:</b> When you highlight a file and press <code>Delete</code>, it isn't actually erased. It is moved to the Recycle Bin.</li><li><b>Restoring:</b> Double-click the Recycle Bin on your desktop. Find your file, right-click it, and select \"Restore\". It will teleport back to exactly where it was before you deleted it!</li><li><b>Permanent Deletion:</b> If you need to free up disk space, right-click the Recycle Bin icon and select \"Empty Recycle Bin\". This action is irreversible.</li><li><b>Bypass:</b> Hold <code>Shift</code> while pressing <code>Delete</code> to bypass the Recycle Bin and instantly destroy the file permanently. Use with caution!</li></ul>"
    },
    "zipping": {
        "title": "Compressing Files (Zipping) Help",
        "content": "<h2>Compressing Files (Zipped Folders)</h2><p>Zipping files allows you to bundle multiple files into a single archive and compress their data size, making them easier to email or store.</p><h3>How to Zip and Unzip</h3><ul><li><b>To Zip:</b> Highlight one or more files, right-click, select <b>Send To</b>, and click <b>Compressed (zipped) Folder</b>. A new file with a zipper icon will appear.</li><li><b>To Unzip:</b> Right-click a zip file and select <b>Extract All...</b>. A wizard will guide you to choose a destination folder where the uncompressed files will be placed.</li><li><b>Native Browsing:</b> Windows XP treats Zip files like normal folders! You can double-click a zip file to look inside it without extracting it first.</li></ul>"
    },
    "clipbook": {
        "title": "Clipbook Viewer Help",
        "content": "<h2>Clipbook Viewer Overview</h2><p>The Clipbook Viewer allows you to see exactly what is currently stored in your computer's RAM \"Clipboard\".</p><h3>How it Works</h3><ul><li>Whenever you press <code>Ctrl+C</code> or Edit > Copy, the data is placed on the Clipboard.</li><li>Open the Clipbook Viewer to see that data. If it's text, you'll see text. If it's an image, you'll see a preview.</li><li><b>Security:</b> If you copied a sensitive password and want to remove it from memory, open Clipbook Viewer and go to Edit > Delete to clear the clipboard buffer.</li></ul>"
    },
    "dragdrop": {
        "title": "File Drag-and-Drop Help",
        "content": "<h2>File Drag-and-Drop Capabilities</h2><p>The Windows XP simulator supports modern web drag-and-drop APIs!</p><h3>How to use</h3><p>Simply grab a file from your actual host computer's operating system (like Windows 10/11, macOS, or Linux) and drop it directly into the simulator browser window.</p><ul><li><b>Images (.png, .jpg, .gif):</b> Can be viewed in Picture and Fax Viewer or edited in Paint.</li><li><b>Text (.txt, .js, .css, .html):</b> Will automatically open in Notepad for inspection.</li><li><b>Audio (.mp3, .wav):</b> Can be played back via the Media Player.</li></ul><p>This is the fastest way to import data into the simulated environment.</p>"
    },
    "sfx": {
        "title": "System Sound Effects Help",
        "content": "<h2>System Sound Effects Overview</h2><p>Windows XP is famous for its iconic sound design, composed primarily of retro <code>.wav</code> files.</p><h3>Iconic Sounds</h3><ul><li><b>Windows XP Startup:</b> The legendary 6-second orchestral sweep that plays when logging in.</li><li><b>Critical Stop:</b> The harsh \"ding\" associated with error dialogs.</li><li><b>Hardware Insert/Remove:</b> The two-tone \"da-dum\" and \"dum-da\" sounds when plugging in USB flash drives.</li></ul><p>You can customize or mute all system sounds by going to Control Panel > Sounds and Audio Devices.</p>"
    },
    "charmap": {
        "title": "Character Map Help",
        "content": "<h2>Character Map Overview</h2><p>Character Map (charmap.exe) is a utility to insert symbols, foreign characters, and wingdings that do not exist on a standard keyboard.</p><h3>How to Use</h3><ul><li>Open Character Map from Accessories > System Tools.</li><li>Select a font from the dropdown (e.g., Arial, Times New Roman, or Wingdings).</li><li>Find the symbol you want (like ©, ™, or a smiley face), click it, and click \"Select\".</li><li>Click \"Copy\" to put it on your clipboard, then paste it into Notepad, WordPad, or FrontPage.</li></ul><p><b>Pro Tip:</b> Notice the \"Keystroke\" hint at the bottom right. E.g., Alt+0169 types the Copyright symbol instantly without opening Character Map!</p>"
    },
    "run": {
        "title": "Run Command Help",
        "content": "<h2>Run Dialog Overview</h2><p>The Run dialog (accessed via Start Menu > Run, or pressing Windows Key + R) allows you to bypass the UI and directly launch executables or open directories.</p><h3>Common Run Commands</h3><ul><li><code>cmd</code>: Opens the Command Prompt.</li><li><code>regedit</code>: Opens the Windows Registry Editor.</li><li><code>msconfig</code>: System Configuration Utility (manage startup programs).</li><li><code>calc</code>: Launches Calculator.</li><li><code>notepad</code>: Launches Notepad.</li><li><code>mspaint</code>: Launches MS Paint.</li><li><code>C:\\\\</code>: Instantly opens an Explorer window at the root of your hard drive.</li></ul>"
    },
    "outlook": {
        "title": "Outlook Express Help",
        "content": "<h2>Outlook Express Overview</h2><p>Outlook Express is the built-in email and newsgroup client included with Windows XP. It provides a simple interface to manage your digital correspondence.</p><h3>Key Features</h3><ul><li><b>Inbox:</b> Check for new mail using the Send/Recv button. Emails are sorted chronologically.</li><li><b>Address Book:</b> Manage your contacts, email addresses, and phone numbers.</li><li><b>Identities:</b> Different users on the same computer can set up separate Identities to keep their emails private without needing separate Windows accounts.</li></ul><p><b>Note:</b> In this simulator, Outlook Express is primarily for demonstration, but you can read pre-loaded lore emails!</p>"
    },
    "pinball": {
        "title": "3D Pinball: Space Cadet Help",
        "content": "<h2>3D Pinball for Windows - Space Cadet</h2><p>3D Pinball is the legendary digital pinball game included in Microsoft Plus! 95 and Windows XP.</p><h3>How to Play</h3><ul><li><b>Plunger:</b> Hold down the Spacebar to pull back the plunger, release to launch the ball.</li><li><b>Flippers:</b> Use the 'Z' key for the left flipper and '/' for the right flipper.</li><li><b>Nudging:</b> Use 'X', '.', and 'Up Arrow' to bump the table and save a draining ball. Careful not to \"Tilt\" the machine!</li></ul><p><b>Goal:</b> Complete missions by hitting specific targets to rank up your cadet from Ensign all the way to Fleet Admiral!</p><div style='background:#FFFDE8; border:1px solid #D6D2B0; padding:10px; border-radius:5px; margin-top:10px;'><h4 style='margin:0 0 5px 0; color:#494949;'>Did you know?</h4><p style='font-size:11px; margin:0;'>Type the secret code <code>hidden test</code> while playing to enable debug mode. Then you can literally click and drag the pinball around the table with your mouse to cheat!</p></div>"
    }
};

window.helpHistoryList = [];
window.showHelpTopic = function(topicId) {
    if (!window.helpData || !window.helpData[topicId]) return;
    let area = document.getElementById('help-content-area');
    if (!area) return;
    area.innerHTML = window.helpData[topicId].content || window.helpData[topicId];
    area.scrollTop = 0;
    if (window.helpHistoryList[window.helpHistoryList.length - 1] !== topicId) {
        window.helpHistoryList.push(topicId);
    }
};

window.helpHistoryBack = function() {
    if (window.helpHistoryList.length > 1) {
        window.helpHistoryList.pop();
        let prev = window.helpHistoryList.pop(); 
        window.showHelpTopic(prev);
    }
};

window.helpHistoryForward = function() {
    // Unimplemented yet
};

window.openHelpTopic = function(topicId) {
    if (typeof window.openProgram === 'function') {
        let helpWin = document.getElementById('help-window');
        if (!helpWin || helpWin.style.display === 'none') {
            window.openProgram('help-window');
        } else {
            window.bringToFront(helpWin);
        }
    }
    window.showHelpTopic(topicId);
};

// ===== HELP SEARCH =====
window.helpSearch = function() {
    let input = document.getElementById('help-search-input');
    if (!input) return;
    let q = input.value.trim().toLowerCase();
    if (!q) return;

    let content = document.getElementById('help-content-area');
    if (!content) return;

    // Search through all topics
    let matches = [];
    for (let id in window.helpData) {
        let topic = window.helpData[id];
        let titleMatch = topic.title && topic.title.toLowerCase().includes(q);
        // Strip HTML tags from content for searching
        let plainContent = (topic.content || '').replace(/<[^>]+>/g, ' ').toLowerCase();
        let bodyMatch = plainContent.includes(q);
        if (titleMatch || bodyMatch) {
            matches.push({ id: id, title: topic.title, titleMatch: titleMatch });
        }
    }

    if (matches.length === 0) {
        content.innerHTML = `
            <div style="padding:20px; font-family:Tahoma; font-size:12px;">
                <h2 style="color:#215DC6;">Search Results</h2>
                <p>No results found for <b>"${q}"</b>.</p>
                <p>Try a different search term, or <a href="#" onclick="showHelpTopic('home')">return to the Help home page</a>.</p>
            </div>
        `;
        return;
    }

    // If exactly one match, jump straight to it
    if (matches.length === 1) {
        window.showHelpTopic(matches[0].id);
        return;
    }

    // Otherwise show a results list
    let resultsHtml = matches.map(m =>
        `<li style="margin-bottom:8px;">
            <a href="#" onclick="showHelpTopic('${m.id}')" style="color:#003399; font-size:12px;">${m.title}</a>
        </li>`
    ).join('');

    content.innerHTML = `
        <div style="padding:20px; font-family:Tahoma; font-size:12px;">
            <h2 style="color:#215DC6;">Search Results for "${q}"</h2>
            <p>${matches.length} result(s) found:</p>
            <ul style="list-style:disc; padding-left:20px;">
                ${resultsHtml}
            </ul>
            <p style="margin-top:16px;"><a href="#" onclick="showHelpTopic('home')">⮜ Return to Help Home</a></p>
        </div>
    `;
};



